        Vec3 p_off = add(p, mul(n, 0.001f));
        int in_shadow = hit_sphere(p_off, light_dir, center, 1.0f) > 0;
        float diffuse = in_shadow ? 0.0f : fmaxf(0.0f, dot(n, light_dir));
        return mul(base, 0.2f + 0.8f * diffuse);
    }

    float t = 0.5f * (d.y + 1.0f);
    return add(mul((Vec3){1.0f, 1.0f, 1.0f}, 1.0f - t), mul((Vec3){0.5f, 0.7f, 1.0f}, t));
}

